import{_ as t,a,b as s}from"./chunks/支持留言.NiGCLVdp.js";import{_ as i,o,c as l,a2 as p}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Blog","description":"","frontmatter":{},"headers":[],"relativePath":"bn-BD/Other/blog.md","filePath":"bn-BD/Other/blog.md","lastUpdated":1781962217000}'),n={name:"bn-BD/Other/blog.md"};function r(c,e,d,g,h,u){return o(),l("div",null,[...e[0]||(e[0]=[p('<h1 id="blog" tabindex="-1">Blog <a class="header-anchor" href="#blog" aria-label="Permalink to &quot;Blog&quot;">​</a></h1><p>Blog feature আপনার ImgBed site-এ একটি standalone blog page যোগ করে।</p><p>Enable করার পর visitors খুলতে পারবে:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/blog/</span></span></code></pre></div><p><img src="'+t+'" alt="Blog homepage" loading="lazy"></p><p>Blog open-source <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a> project থেকে adapted। ImgBed এটিকে rewrite করে Vue-এর সঙ্গে integrate করে, যাতে image hosting site-এর অংশ হিসেবে চলতে পারে।</p><h2 id="কোথায়-configure-করবেন" tabindex="-1">কোথায় Configure করবেন <a class="header-anchor" href="#কোথায়-configure-করবেন" aria-label="Permalink to &quot;কোথায় Configure করবেন&quot;">​</a></h2><p>Blog settings এখানে:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Blog</span></span></code></pre></div><p><img src="'+a+'" alt="Blog settings" loading="lazy"></p><h2 id="first-time-setup" tabindex="-1">First-Time Setup <a class="header-anchor" href="#first-time-setup" aria-label="Permalink to &quot;First-Time Setup&quot;">​</a></h2><ol><li><code>Enable</code> on করুন।</li><li>Blog configuration store করার জন্য GitHub account নির্বাচন করুন।</li><li><code>Update Blog</code> ক্লিক করুন।</li><li>Success message আসা পর্যন্ত অপেক্ষা করুন।</li><li>Blog দেখতে <code>https://your-domain.com/blog/</code> খুলুন।</li></ol><p>প্রথম ব্যবহারেই ImgBed selected account-এর নিচে একটি private GitHub repository তৈরি করে:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>এই repository blog settings এবং article content সংরক্ষণ করে।</p><h2 id="posts-লেখা" tabindex="-1">Posts লেখা <a class="header-anchor" href="#posts-লেখা" aria-label="Permalink to &quot;Posts লেখা&quot;">​</a></h2><p>Blog posts আপনার private GitHub repository-তে edit করুন:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Typical workflow:</p><ol><li>GitHub খুলুন।</li><li>Private <code>imgbed-blog-config</code> repository-তে যান।</li><li>Post files edit বা add করুন।</li><li>Changes commit করুন।</li><li>ImgBed admin panel-এ ফিরে <code>Update Blog</code> ক্লিক করুন, অথবা blog homepage-এর upper-left corner-এর logo তিনবার ক্লিক করে blog update trigger করুন।</li></ol><p><code>Update Blog</code> আপনার লেখা content overwrite করে না। দরকার হলে repository initialize করে এবং blog cache refresh করে।</p><h2 id="supported-features" tabindex="-1">Supported Features <a class="header-anchor" href="#supported-features" aria-label="Permalink to &quot;Supported Features&quot;">​</a></h2><p>Blog post lists, categories, tags, archives, search, dark mode এবং language switching-এর মতো common blog features support করে।</p><p>Comments এবং visit statistics-ও support করে।</p><p><img src="'+s+'" alt="Blog comments" loading="lazy"></p><p>Comments posts-এর নিচে দেখা যায়। Visitors avatar, nickname, email এবং comment content submit করতে পারে।</p><p>Visit statistics post views এবং site visits দেখায়, যা blog traffic বোঝাতে সাহায্য করে।</p><h2 id="url" tabindex="-1">URL <a class="header-anchor" href="#url" aria-label="Permalink to &quot;URL&quot;">​</a></h2><p>Blog সবসময় <code>/blog/</code>-এর নিচে serve হয়।</p><p>যেমন, আপনার ImgBed domain যদি হয়:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>তাহলে blog URL হবে:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>Blog disabled হলে visitors আর blog page access করতে পারবে না।</p>',34)])])}const f=i(n,[["render",r]]);export{v as __pageData,f as default};
